-- 获取红点(主界面使用，不显示具体数量)
function LxRedPointCtrl:GetRedNum(funcRefId)
    if not CtrlCenter.FuncOpen:IsFuncOpen(funcRefId, FuncOpenTipsEnum.None) then
        return 0
    end

    local num = 0
    if funcRefId == FuncOpnIdConst.Equip then
        num = self:GetEquipRedNum()
    elseif funcRefId == FuncOpnIdConst.Rank then
        num = self:GetRankRedNum()
    elseif funcRefId == FuncOpnIdConst.Guild then
        num = self:GetGuildRedNum()
    elseif funcRefId == FuncOpnIdConst.Friend then
        num = self:GetFriendRedNum()
    elseif funcRefId == FuncOpnIdConst.PlayGamesDevelop then
        num = self:GetPlayGamesDevelopRedNum()
    elseif funcRefId == FuncOpnIdConst.PlayGamesPve then
        num = ModuleCenter.CrestGame:GetCrestGameRed()
        if num<=0 then num= ModuleCenter.BadgeGame:GetBadgeGameRed() end
    elseif funcRefId == FuncOpnIdConst.Role then
        num = ModuleCenter.Crest:GetCrestRed()
        if num<=0 then num = self:GetClothesRed() end
    elseif funcRefId == FuncOpnIdConst.CrestGame then
        num = ModuleCenter.CrestGame:GetCrestGameRed()
    elseif funcRefId == FuncOpnIdConst.DailyTask then
        num = ModuleCenter.Quest:DailyTaskRed()
    elseif funcRefId == FuncOpnIdConst.TimeMachineEntrance then
        num = CtrlCenter.HeroCall:GetHeroCallRed()
    elseif funcRefId == FuncOpnIdConst.InstanceEntrance then
        num = CtrlCenter.Instance:GetInstanceRed()
    elseif funcRefId == FuncOpnIdConst.BadgeGame then
        num = ModuleCenter.BadgeGame:GetBadgeGameRed()
    elseif funcRefId == FuncOpnIdConst.Explorer then
        num = self:GetExplorerRedNum()
    elseif funcRefId == FuncOpnIdConst.Clothes then
        num = self:GetClothesRed()
    elseif funcRefId == FuncOpnIdConst.Crest then
        num = ModuleCenter.Crest:GetCrestRed()
    elseif funcRefId == FuncIds.Hero then -- 英雄总红点
        num = self:GetHeroAllRedNum()
    elseif funcRefId == FuncIds.HeroList then -- 英雄列表
        num = self:GetHeroTrainRedNum()
    elseif funcRefId == FuncIds.BookHeroTrain then -- 英雄图鉴
        num = self:GetHeroBookRedNum()
    elseif funcRefId == FuncIds.HeroCompound then -- 英雄合成
        num = self:GetHeroCompoundRedNum()
    elseif funcRefId == FuncOpnIdConst.HeroFavorability then
    end

    return num
end

-- 获取装备红点
function LxRedPointCtrl:GetEquipRedNum()
    if ModuleCenter.Equip:IsHadBatterEquip() then
        return 1
    end

    if ModuleCenter.Equip:IsCanStrengthEquip() then
        return 1
    end
    return 0
end

-- 排行榜红点
function LxRedPointCtrl:GetRankRedNum()
    local num = ModuleCenter.Rank:GetRankLikeRedNum()
    if num > 0 then
        return num
    end
    return ModuleCenter.Rank:GetMilestoneRedNum()
end

-- 军团红点
function LxRedPointCtrl:GetGuildRedNum()
    if not CtrlCenter.Guild:HadGuild() then
        return 0
    end

    local num = CtrlCenter.Guild:GetPlayerApplyRedNum()
    if num > 0 then
        return num
    end
    return CtrlCenter.Guild:GetDonateRedNum()
end

-- 好友红点
function LxRedPointCtrl:GetFriendRedNum()
    local num = ModuleCenter.Friend:GetApplyRedNum()
    if num > 0 then
        return num
    end
    return ModuleCenter.Friend:GetCanReceiveLoveNum()
end

function LxRedPointCtrl:GetExplorerRedNum()
    local refId = ModuleCenter.Role:GetRoleExplorerLevel()
    local explorerRef = GameTable.ExplorerLevelRef[refId]
    local questInfo = ModuleCenter.Quest:GetQuest(explorerRef.needQuest)
    if questInfo and questInfo.state == 2 then 
        local curPower = tonumber(ModuleCenter.Role:GetRolePower())
        if explorerRef.needPower<=curPower then 
            local const = not tonumber(explorerRef.needItem[1]) and LxDataHelper.ParseItemList(explorerRef.needItem) or nil
            return  (const and CtrlCenter.Item:CheckItemListEnough(const,false)) and 1 or 0 
        end
    end
    return 0
end

function LxRedPointCtrl:GetClothesRed()
    if not CtrlCenter.FuncOpen:IsFuncShow(FuncOpnIdConst.Clothes) then return 0 end
    local partRef = GameTable.ClothesPartRef
    for _, v in ipairs(partRef) do  
        if ModuleCenter.Clothes:GetClothesRed(v.refId)>0 then return 1 end
    end
    return ModuleCenter.Clothes:GetClothesCollectRed()
end


-- 获取养成类红点
function LxRedPointCtrl:GetPlayGamesDevelopRedNum()
    for k, ref in ipairs(ModuleCenter.PlayGames:GetPlayGamesRefList(PlayGamesType.Develop)) do
        if self:GetRedNum(ref.jumpId) > 0 then
            return 1
        end
    end
    return 0
end

