-- 红点变化
function LxRedPointCtrl:OnChangeRed()
    if os.clock() - self._redTime < 0.2 then
        self._needFire = true
        return
    end

    self:FireRedEvent()
    self:StopTimer("nextFire")
    self:StartTimer("nextFire", 0.2, false, 0, function()
        self:FireRedEvent()
    end)
end

-- 发送红点变化事件
function LxRedPointCtrl:FireRedEvent()
    FireEvent(EventNames.RED_CHANGE)
    self._redTime = os.clock()
    self._needFire = false
end

return LxRedPointCtrl
